INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-08', '02:42:43', 37, 19, 3, 0, 0, 164, 59, 35.98, 'https://x.com/sandmark_news/status/2052579924142092393', 'On US leadership and the liquidity gap:  "The US has the fundamentals, the talent pool, the financial markets… traditional regulatory frameworks. The US right now is leading the world in terms of [crypto] policies... Now we are seeing the developers coming back. What is a little bit lagging in the US right now is the liquidity, so the best liquidity in crypto is outside the US… Binance has the best liquidity in this market and we'd love to be able to provide that in some way, either revitalizing Binance or somehow providing the US the best liquidity in the world."', NULL);
